package core.runtime.org.apache.isis.core.runtime.runner.opts;

public class OptionHandlerPassword extends OptionHandlerAbstract { private String password ; public OptionHandlerPassword ( ) { super ( ) ; } @ Override @ SuppressWarnings ( "static-access" ) public void addOption ( final Options options ) { final Option option = OptionBuilder . withArgName ( "password" ) . hasArg ( ) . withLongOpt ( PASSWORD_LONG_OPT ) . withDescription ( "password to automatically log in with" ) . create ( PASSWORD_OPT ) ; options . addOption ( option ) ; } @ Override public boolean handle ( final CommandLine commandLine , final BootPrinter bootPrinter , final Options options ) { password = commandLine . getOptionValue ( Constants . PASSWORD_OPT ) ; return true ; } @ Override public void prime ( final IsisConfigurationBuilder isisConfigurationBuilder ) { isisConfigurationBuilder . add ( SystemConstants . PASSWORD_KEY , password ) ; } public String getPassword ( ) { return password ; } }